{"command":["pwsh.exe","-NoProfile","-Command","$ErrorActionPreference='Stop'
$kb = 'D:\AI_Projects\.TelegramChatHistory\Workspace\VisaAchknowlegeBase'
$indexPath = Join-Path $kb 'Index.yaml'
$presetPath = Join-Path $kb 'PresetServiceCollections.yaml'
$ambigPath = Join-Path $kb 'AmbiguousTermsDictionary.yaml'

# Read files if exist
$index = if (Test-Path $indexPath) { Get-Content -Raw -LiteralPath $indexPath } else { '' }
$preset = if (Test-Path $presetPath) { Get-Content -Raw -LiteralPath $presetPath } else { '' }
$ambig = if (Test-Path $ambigPath) { Get-Content -Raw -LiteralPath $ambigPath } else { '' }

[pscustomobject]@{ IndexLen=$index.Length; PresetLen=$preset.Length; AmbigLen=$ambig.Length } | Format-List

# Gather all md files under departments
$docs = Get-ChildItem -LiteralPath $kb -Recurse -File -Filter '*.md'
$docs | Select-Object FullName | Format-Table -AutoSize | Out-String -Width 200 | Write-Output

# Extract frontmatter from each markdown
$fronts = @()
foreach ($f in $docs) {
  $txt = Get-Content -Raw -LiteralPath $f.FullName
  if ($txt -match "(?s)^---\s*(.*?)\s*---") {
    $yaml = $matches[1]
  } else { $yaml = '' }
  $fronts += [pscustomobject]@{ Path=$f.FullName; Front=$yaml }
}

# Simple YAML parse for key fields using regex patterns (best-effort)
$parsed = foreach ($fm in $fronts) {
  $y = $fm.Front
  $get = {
    param($key,$yml)
    if ($yml -match "(?m)^\s*" + [regex]::Escape($key) + "\s*:\s*(.*)$") { ($matches[1]).Trim() } else { '' }
  }
  [pscustomobject]@{
    Path = $fm.Path
    name = &$get 'name' $y
    slug = &$get 'slug' $y
    type = &$get 'type' $y
    department = &$get 'department' $y
    aliases = if ($y -match "(?s)aliases\s*:\s*\[(.*?)\]") { ($matches[1] -replace '"','' -split ',\s*') } else { @() }
    related_present = $y -match "(?m)^related_businesses\s*:"
    docs_must_present = $y -match "(?m)^documents_must_provide\s*:"
    docs_can_present = $y -match "(?m)^documents_can_produce\s*:"
    docs_out_present = $y -match "(?m)^documents_output\s*:"
  }
}

$parsed | Format-Table -AutoSize | Out-String -Width 240 | Write-Output
"],"timeout_ms":120000}

{"command":["pwsh.exe","-NoProfile","-Command","$ErrorActionPreference='Stop'
$kb = 'D:\AI_Projects\.TelegramChatHistory\Workspace\VisaAchknowlegeBase'

function Get-FrontmatterObject($path){
  $txt = Get-Content -Raw -LiteralPath $path
  $o = [ordered]@{ path=$path; department=(Split-Path (Split-Path $path -Parent) -Leaf); name=''; slug=''; type=''; aliases=@(); related_businesses=@(); documents_must_provide=@(); documents_can_produce=@(); documents_output=@() }
  if ($txt -notmatch "(?s)^---\s*(.*?)\s*---") { return $o }
  $yaml = $matches[1]
  $getVal = {
    param($key)
    if ($yaml -match "(?m)^\s*" + [regex]::Escape($key) + "\s*:\s*(.+)$") { ($matches[1]).Trim().Trim('"') } else { '' }
  }
  $o.name = & $getVal 'name'
  $o.slug = & $getVal 'slug'
  $o.type = & $getVal 'type'
  $oDept = & $getVal 'department'
  if ($oDept) { $o.department = $oDept }
  # generic list extractor
  function Get-List([string]$key){
    $pat = "(?s)\n\s*" + [regex]::Escape($key) + "\s*:\s*(?:\n|\r\n)((?:\s*-\s*.+?(?:\r?\n))+)">
    if ($yaml -match $pat) {
      $block = $matches[1]
      return ($block -split "\r?\n") | Where-Object { $_ -match "-\s*(.+)" } | ForEach-Object { $matches[1].Trim().Trim('"') }
    }
    if ($yaml -match "(?s)" + [regex]::Escape($key) + "\s*:\s*\[(.*?)\]") { return ($matches[1] -split ',') | ForEach-Object { $_.Trim().Trim('"') } }
    return @()
  }
  $o.aliases = Get-List 'aliases'
  $o.related_businesses = Get-List 'related_businesses'
  $o.documents_must_provide = Get-List 'documents_must_provide'
  $o.documents_can_produce = Get-List 'documents_can_produce'
  $o.documents_output = Get-List 'documents_output'
  return $o
}

$docs = Get-ChildItem -LiteralPath $kb -Recurse -File -Filter '*.md'
$objs = @()
foreach ($f in $docs) { $objs += Get-FrontmatterObject $f.FullName }

# Summary counts
$departments = $objs | Group-Object department | Sort-Object Count -Descending | Select-Object Name,Count
$namesMissing = $objs | Where-Object { -not $_.name }
$slugsMissing = $objs | Where-Object { -not $_.slug }
$relatedCount = ($objs | Where-Object { $_.related_businesses.Count -gt 0 }).Count

[pscustomobject]@{
  TotalDocs = $objs.Count
  Departments = ($departments | ForEach-Object { $_.Name+':' + $_.Count }) -join '; '
  MissingNames = $namesMissing.Count
  MissingSlugs = $slugsMissing.Count
  WithRelated = $relatedCount
} | Format-List

# Detect asymmetric relationships (A lists B but B does not list A)
$pathBySlug = @{}
foreach ($o in $objs) { if ($o.slug) { $pathBySlug[$o.slug] = $o } }
$asym = @()
foreach ($o in $objs) {
  foreach ($rel in $o.related_businesses) {
    $b = $pathBySlug[$rel]
    if ($null -ne $b) {
      if (-not ($b.related_businesses -contains $o.slug)) {
        $asym += [pscustomobject]@{ A=$o.slug; B=$b.slug; APath=$o.path; BPath=$b.path }
      }
    }
  }
}
$asym | Select-Object -First 20 | Format-Table -AutoSize | Out-String -Width 220 | Write-Output

# Duplicate or ambiguous names/aliases
$nameMap = @{}
$collisions = @()
foreach ($o in $objs) {
  $keys = @()
  if ($o.name) { $keys += $o.name.ToLowerInvariant() }
  foreach ($al in $o.aliases) { if ($al) { $keys += $al.ToLowerInvariant() } }
  foreach ($k in ($keys | Select-Object -Unique)) {
    if ($nameMap.ContainsKey($k)) {
      $collisions += [pscustomobject]@{ term=$k; one=$nameMap[$k].slug; two=$o.slug }
    } else { $nameMap[$k] = $o }
  }
}
$collisions | Select-Object -First 20 | Format-Table -AutoSize | Out-String -Width 200 | Write-Output

# Prepare simple report file paths
$report = Join-Path $kb 'final_audit_report.txt'
"OK" | Set-Content -LiteralPath $report
"],"timeout_ms":120000}
